/**
 * AdminStudentIDCards.tsx — GMS Taj Muhammad
 *
 * KEY DESIGN DECISIONS (portrait ID card matching reference):
 * ─ Front: blue header, centered photo, student name, detail rows, QR, footer
 * ─ Back: blue header, terms & conditions, signature lines, footer
 * ─ Card size: CR80 portrait = 54 × 85.6 mm → rendered at 638 × 1012 px (300 dpi)
 * ─ FRONT and BACK are SEPARATE canvases so each prints perfectly on its own
 * ─ HD: canvas at 300 dpi equivalent, no blur
 * ─ Logo: embedded base64 — always shows regardless of network/settings
 * ─ Cards auto-render in the list; admin clicks "Download Front" / "Download Back"
 * ─ Admin can download one student or entire class/school in a ZIP
 */

import { useState, useEffect, useCallback } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/lib/supabase";
import { useSchoolSettings, safeMediaUrl } from "@/hooks/useSchoolSettings";
import {
  Download, Loader2, Search, Users, ChevronDown, CreditCard, X, ZoomIn, Trash2
} from "lucide-react";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import toast from "react-hot-toast";
import QRCode from "qrcode";

// ── Embedded logo (GMS Taj Muhammad seal, 200×200 PNG) ──────────────────────────
const LOGO_B64 = "";
const LOGO_SRC = `data:image/png;base64,${LOGO_B64}`;
const SIG_SRC = "data:image/png;base64,";

// ── Types ─────────────────────────────────────────────────────────────────────
interface Student {
  id: string;
  full_name: string;
  roll_number: string;
  class: string;
  father_name: string | null;
  photo_url: string | null;
  is_active: boolean;
  // Admin-editable overrides (in-memory only)
  session?: string;
  serial_no?: string;
  emis_code?: string;
}

// ── Card dimensions (300 dpi, CR80 Portrait) ──────────────────────────────────
// 54mm × 85.6mm at 300dpi = 638px × 1012px → portrait orientation
const W = 638;
const H = 1012;

const CLASSES = ["6", "7", "8"];

// ── Helpers ───────────────────────────────────────────────────────────────────
function loadImage(src: string): Promise<HTMLImageElement> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => resolve(img);
    img.onerror = () => reject(new Error("img failed: " + src.slice(0, 60)));
    img.src = src;
  });
}

function rrect(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, r: number) {
  ctx.beginPath();
  ctx.moveTo(x + r, y);
  ctx.lineTo(x + w - r, y); ctx.arcTo(x + w, y, x + w, y + r, r);
  ctx.lineTo(x + w, y + h - r); ctx.arcTo(x + w, y + h, x + w - r, y + h, r);
  ctx.lineTo(x + r, y + h); ctx.arcTo(x, y + h, x, y + h - r, r);
  ctx.lineTo(x, y + r); ctx.arcTo(x, y, x + r, y, r);
  ctx.closePath();
}

async function makeQR(s: Student): Promise<string> {
  return QRCode.toDataURL(
    `GMS Taj Muhammad\nName: ${s.full_name}\nClass: ${s.class}\nRoll: ${s.roll_number}${s.father_name ? `\nFather: ${s.father_name}` : ""}`,
    { width: 220, margin: 1, color: { dark: "#1a1a2e", light: "#ffffff" }, errorCorrectionLevel: "M" }
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
//  FRONT CARD RENDERER — Portrait Layout
//  Vertical flow: header → photo → name → details → QR → footer
// ═══════════════════════════════════════════════════════════════════════════════
async function renderFront(student: Student, qrDataUrl: string): Promise<string> {
  const SCALE = 3;
  const canvas = document.createElement("canvas");
  canvas.width = W * SCALE;
  canvas.height = H * SCALE;
  const ctx = canvas.getContext("2d")!;
  ctx.scale(SCALE, SCALE);
  ctx.imageSmoothingEnabled = true;
  ctx.imageSmoothingQuality = "high";
  ctx.textBaseline = "alphabetic";

  // Palette
  const NAVY = "#0078d4";
  const BLUE = "#50b0f0";
  const SOFT = "#eaf4fb";
  const TEXT = "#0f172a";
  const MUTED = "#64748b";

  // ── 1. Card background ─────────────────────────────────────────────────────
  ctx.fillStyle = "#ffffff";
  rrect(ctx, 0, 0, W, H, 22);
  ctx.fill();
  ctx.strokeStyle = "#cfe8f7";
  ctx.lineWidth = 1;
  rrect(ctx, 0.5, 0.5, W - 1, H - 1, 22);
  ctx.stroke();

  // ── 2. Header bar (royal blue, ~15% of card) ───────────────────────────────
  const HDR_H = 120;
  ctx.save();
  rrect(ctx, 0, 0, W, HDR_H + 22, 22);
  ctx.clip();
  ctx.fillStyle = NAVY;
  ctx.fillRect(0, 0, W, HDR_H);
  ctx.restore();

  // Thin accent line below header
  ctx.fillStyle = BLUE;
  ctx.fillRect(0, HDR_H, W, 2);

  // Logo (circle, left side of header)
  const LOGO_SZ = 64;
  const LOGO_X = 24;
  const LOGO_Y = (HDR_H - LOGO_SZ) / 2;
  try {
    const logo = await loadImage(LOGO_SRC);
    ctx.save();
    ctx.beginPath();
    ctx.arc(LOGO_X + LOGO_SZ / 2, LOGO_Y + LOGO_SZ / 2, LOGO_SZ / 2, 0, Math.PI * 2);
    ctx.fillStyle = "#ffffff";
    ctx.fill();
    ctx.clip();
    ctx.drawImage(logo, LOGO_X + 2, LOGO_Y + 2, LOGO_SZ - 4, LOGO_SZ - 4);
    ctx.restore();
  } catch { /* skip */ }

  // School name (right of logo, centered vertically in header)
  const TXT_X = LOGO_X + LOGO_SZ + 10;
  ctx.fillStyle = "#ffffff";
  ctx.font = "bold 18px 'Georgia', serif";
  ctx.textAlign = "left";
  ctx.fillText("GMS TAJ MUHAMMAD", TXT_X, HDR_H / 2 - 14);
  ctx.fillStyle = "#d9ecf9";
  ctx.font = "10px 'Georgia', serif";
  ctx.fillText("Govt. Middle School · Mohmand · KPK", TXT_X, HDR_H / 2 + 2);
  ctx.font = "9px 'Georgia', serif";
  ctx.fillStyle = "#b0d4f1";
  ctx.fillText(`Session ${student.session ?? `${new Date().getFullYear()}–${new Date().getFullYear() + 1}`}`, TXT_X, HDR_H / 2 + 16);

  // "STUDENT ID CARD" right side
  ctx.textAlign = "right";
  ctx.fillStyle = "#ffffff";
  ctx.font = "bold 11px 'Georgia', serif";
  ctx.fillText("STUDENT ID CARD", W - 16, HDR_H / 2 - 8);
  ctx.font = "9px 'Georgia', serif";
  ctx.fillStyle = "#b0d4f1";
  ctx.fillText("EMIS: 66013", W - 16, HDR_H / 2 + 6);
  ctx.textAlign = "left";

  // ── 3. Photo — centered below header ───────────────────────────────────────
  const PHOTO_SZ = 160;
  const PHOTO_X = (W - PHOTO_SZ) / 2;
  const PHOTO_Y = HDR_H + 18;

  // Soft blue frame
  ctx.fillStyle = SOFT;
  rrect(ctx, PHOTO_X - 6, PHOTO_Y - 6, PHOTO_SZ + 12, PHOTO_SZ + 12, 10);
  ctx.fill();

  let photoOk = false;
  if (student.photo_url) {
    try {
      const ph = await loadImage(safeMediaUrl(student.photo_url)!);
      ctx.save();
      rrect(ctx, PHOTO_X, PHOTO_Y, PHOTO_SZ, PHOTO_SZ, 6);
      ctx.clip();
      const sc = Math.max(PHOTO_SZ / ph.width, PHOTO_SZ / ph.height);
      const sw = PHOTO_SZ / sc, sh = PHOTO_SZ / sc;
      const sx = (ph.width - sw) / 2;
      const sy = (ph.height - sh) / 2;
      ctx.drawImage(ph, sx, sy, sw, sh, PHOTO_X, PHOTO_Y, PHOTO_SZ, PHOTO_SZ);
      ctx.restore();
      photoOk = true;
    } catch { /* fallthrough */ }
  }
  if (!photoOk) {
    ctx.save();
    rrect(ctx, PHOTO_X, PHOTO_Y, PHOTO_SZ, PHOTO_SZ, 6);
    ctx.clip();
    ctx.fillStyle = "#dbe7f5";
    ctx.fillRect(PHOTO_X, PHOTO_Y, PHOTO_SZ, PHOTO_SZ);
    ctx.fillStyle = "#9bb6d6";
    const cx = PHOTO_X + PHOTO_SZ / 2;
    ctx.beginPath(); ctx.arc(cx, PHOTO_Y + PHOTO_SZ * 0.36, PHOTO_SZ * 0.16, 0, Math.PI * 2); ctx.fill();
    ctx.beginPath(); ctx.arc(cx, PHOTO_Y + PHOTO_SZ * 1.05, PHOTO_SZ * 0.42, 0, Math.PI * 2); ctx.fill();
    ctx.restore();
  }

  // ── 4. Student name — centered, large, bold ────────────────────────────────
  const NAME_Y = PHOTO_Y + PHOTO_SZ + 38;
  ctx.fillStyle = TEXT;
  ctx.font = "bold 24px 'Georgia', serif";
  ctx.textAlign = "center";
  const name = student.full_name.length > 24 ? student.full_name.slice(0, 23) + "…" : student.full_name;
  ctx.fillText(name, W / 2, NAME_Y);

  // Father's name (smaller, muted)
  if (student.father_name) {
    ctx.fillStyle = MUTED;
    ctx.font = "14px 'Georgia', serif";
    ctx.fillText(`S/o  ${student.father_name}`, W / 2, NAME_Y + 28);
  }

  // Divider under name
  const DIV_Y = NAME_Y + (student.father_name ? 48 : 20);
  ctx.strokeStyle = "#e2e8f0";
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.moveTo(30, DIV_Y);
  ctx.lineTo(W - 30, DIV_Y);
  ctx.stroke();

  // ── 5. Detail rows — label-value table, centered ───────────────────────────
  const rows: [string, string][] = [
    ["Roll Number", student.roll_number],
    ["Class", `Class ${student.class}`],
    ["Session", student.session ?? `${new Date().getFullYear()}–${new Date().getFullYear() + 1}`],
    ["Serial No.", student.serial_no ?? `SN-${student.id.slice(0, 6).toUpperCase()}`],
    ["EMIS Code", student.emis_code ?? "66013"],
    ["Status", student.is_active ? "Active" : "Inactive"],
  ];

  const TABLE_X = 36;
  const TABLE_W = W - 72;
  const ROW_Y0 = DIV_Y + 28;
  const ROW_H = 58;
  const LABEL_W = 150;

  for (let i = 0; i < rows.length; i++) {
    const [k, v] = rows[i];
    const y = ROW_Y0 + i * ROW_H;

    // Label (left, muted, uppercase)
    ctx.fillStyle = MUTED;
    ctx.font = "12px 'Georgia', serif";
    ctx.textAlign = "left";
    ctx.fillText(k.toUpperCase(), TABLE_X, y + 18);

    // Value (right of label, bold)
    ctx.fillStyle = TEXT;
    ctx.font = "bold 14px 'Georgia', serif";
    const maxLen = 20;
    const vv = v.length > maxLen ? v.slice(0, maxLen - 1) + "…" : v;
    ctx.fillText(vv, TABLE_X + LABEL_W, y + 18);

    // Row separator
    ctx.strokeStyle = "#eef2f7";
    ctx.lineWidth = 1;
    ctx.beginPath();
    ctx.moveTo(TABLE_X, y + ROW_H - 2);
    ctx.lineTo(TABLE_X + TABLE_W, y + ROW_H - 2);
    ctx.stroke();
  }

  // ── 6. QR code — bottom center, small ──────────────────────────────────────
  const QR_SZ = 90;
  const QR_X = (W - QR_SZ) / 2;
  const QR_Y = ROW_Y0 + rows.length * ROW_H + 20;

  try {
    const qrImg = await loadImage(qrDataUrl);
    ctx.drawImage(qrImg, QR_X, QR_Y, QR_SZ, QR_SZ);
  } catch { /* skip */ }
  ctx.fillStyle = MUTED;
  ctx.font = "9px 'Georgia', serif";
  ctx.textAlign = "center";
  ctx.fillText("Scan to verify", W / 2, QR_Y + QR_SZ + 12);
  ctx.textAlign = "left";

  // ── 7. Footer strip — navy ─────────────────────────────────────────────────
  const FT_H = 36;
  ctx.save();
  rrect(ctx, 0, H - FT_H - 22, W, FT_H + 22, 22);
  ctx.clip();
  ctx.fillStyle = NAVY;
  ctx.fillRect(0, H - FT_H, W, FT_H);
  ctx.restore();

  ctx.fillStyle = "#ffffff";
  ctx.font = "10px 'Georgia', serif";
  ctx.textAlign = "left";
  ctx.fillText(`ID: ${student.id.slice(0, 8).toUpperCase()}`, 16, H - FT_H / 2 + 4);
  ctx.textAlign = "center";
  ctx.fillText("Education · Discipline · Success", W / 2, H - FT_H / 2 + 4);
  ctx.textAlign = "right";
  ctx.fillText("Est. 2005", W - 16, H - FT_H / 2 + 4);
  ctx.textAlign = "left";

  return canvas.toDataURL("image/png", 1.0);
}
// ═══════════════════════════════════════════════════════════════════════════════
//  BACK CARD RENDERER — Portrait Layout
//  Blue header, terms & conditions, signature lines (vertical stack), footer
// ═══════════════════════════════════════════════════════════════════════════════
async function renderBack(student: Student): Promise<string> {
  const SCALE = 3;
  const canvas = document.createElement("canvas");
  canvas.width = W * SCALE; canvas.height = H * SCALE;
  const ctx = canvas.getContext("2d")!;
  ctx.scale(SCALE, SCALE);
  ctx.imageSmoothingEnabled = true;
  ctx.imageSmoothingQuality = "high";

  // ── 1. White card background ──────────────────────────────────────────────
  ctx.fillStyle = "#f5f9ff";
  rrect(ctx, 0, 0, W, H, 22);
  ctx.fill();

  // ── 2. Dashed border ────────────────────────────────────────────────────
  ctx.save();
  ctx.strokeStyle = "#cfe4f7";
  ctx.lineWidth = 2;
  ctx.setLineDash([10, 8]);
  rrect(ctx, 8, 8, W - 16, H - 16, 18);
  ctx.stroke();
  ctx.setLineDash([]);
  ctx.restore();

  // ── 3. Logo watermark centre ────────────────────────────────────────────
  try {
    const wm = await loadImage(LOGO_SRC);
    ctx.save();
    ctx.globalAlpha = 0.055;
    const WM = 220;
    ctx.drawImage(wm, (W - WM) / 2, (H - WM) / 2 + 20, WM, WM);
    ctx.restore();
  } catch { /* skip */ }

  // ── 4. Blue header bar ──────────────────────────────────────────────────
  const BACK_HDR_H = 80;
  ctx.save();
  rrect(ctx, 0, 0, W, BACK_HDR_H + 18, 22);
  ctx.clip();
  ctx.fillStyle = "#0078d4";
  ctx.fillRect(0, 0, W, BACK_HDR_H);
  ctx.restore();

  // Gold accent line
  const bgGold = ctx.createLinearGradient(0, 0, W, 0);
  bgGold.addColorStop(0, "#c8a84b");
  bgGold.addColorStop(0.5, "#f0d060");
  bgGold.addColorStop(1, "#c8a84b");
  ctx.fillStyle = bgGold;
  ctx.fillRect(0, BACK_HDR_H, W, 3);

  // Header text
  ctx.fillStyle = "#ffffff";
  ctx.font = "bold 18px 'Georgia', serif";
  ctx.textAlign = "center";
  ctx.fillText("GMS TAJ MUHAMMAD", W / 2, BACK_HDR_H / 2 - 4);
  ctx.font = "11px 'Georgia', serif";
  ctx.fillStyle = "#d9ecf9";
  ctx.fillText("District Mohmand, KPK", W / 2, BACK_HDR_H / 2 + 16);
  ctx.textAlign = "left";

  // ── 5. Terms & Conditions ─────────────────────────────────────────────────
  const TC_TOP = BACK_HDR_H + 30;
  ctx.fillStyle = "#0078d4";
  ctx.font = "bold 14px 'Georgia', serif";
  ctx.fillText("Terms & Conditions", 24, TC_TOP);

  ctx.strokeStyle = "#cfe4f7";
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.moveTo(24, TC_TOP + 8); ctx.lineTo(W - 24, TC_TOP + 8); ctx.stroke();

  const terms = [
    "1.  This card is the property of GMS Taj Muhammad and must be carried at all times.",
    "2.  If found, please return to the school administration at earliest convenience.",
    "3.  This card is non-transferable. Misuse will result in disciplinary action.",
    "4.  Loss or damage must be reported immediately to the school administration.",
    "5.  Tampering, defacing, or altering this card is strictly prohibited.",
    "6.  The school reserves the right to cancel or replace this card at any time.",
  ];

  ctx.font = "11px 'Georgia', serif";
  ctx.fillStyle = "#106ebe";
  terms.forEach((t, i) => ctx.fillText(t, 24, TC_TOP + 34 + i * 34));

  // Divider after terms
  const TERMS_END = TC_TOP + 34 + terms.length * 34 + 18;
  ctx.strokeStyle = "#cfe4f7";
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.moveTo(24, TERMS_END); ctx.lineTo(W - 24, TERMS_END); ctx.stroke();

  // ── 6. Signature lines — vertical stack (portrait is narrow) ───────────────
  const SIG_Y = TERMS_END + 56;

  // Principal signature
  ctx.strokeStyle = "#4cc2ff";
  ctx.lineWidth = 1.5;
  ctx.beginPath(); ctx.moveTo(60, SIG_Y); ctx.lineTo(W - 60, SIG_Y); ctx.stroke();
  ctx.fillStyle = "#0078d4";
  ctx.font = "bold 12px 'Georgia', serif";
  ctx.textAlign = "center";
  ctx.fillText("Principal's Signature & Stamp", W / 2, SIG_Y + 18);
  ctx.font = "11px 'Georgia', serif";
  ctx.fillStyle = "#50b0f0";
  ctx.fillText("GMS Taj Muhammad", W / 2, SIG_Y + 34);

  // Student signature
  const STUDENT_SIG_Y = SIG_Y + 78;
  ctx.strokeStyle = "#4cc2ff";
  ctx.lineWidth = 1.5;
  ctx.beginPath(); ctx.moveTo(60, STUDENT_SIG_Y); ctx.lineTo(W - 60, STUDENT_SIG_Y); ctx.stroke();
  ctx.fillStyle = "#0078d4";
  ctx.font = "bold 12px 'Georgia', serif";
  ctx.fillText("Student's Signature", W / 2, STUDENT_SIG_Y + 18);
  ctx.font = "11px 'Georgia', serif";
  ctx.fillStyle = "#50b0f0";
  const sName = student.full_name.length > 22 ? student.full_name.slice(0, 20) + "…" : student.full_name;
  ctx.fillText(sName, W / 2, STUDENT_SIG_Y + 34);

  ctx.textAlign = "left";

  // ── 7. Bottom bar ────────────────────────────────────────────────────────
  const BOT_H = 36;
  const BOT_Y = H - BOT_H;
  ctx.save();
  rrect(ctx, 0, BOT_Y - 16, W, BOT_H + 16, 22);
  ctx.clip();
  ctx.fillStyle = "#4cc2ff";
  ctx.fillRect(0, BOT_Y, W, BOT_H);
  ctx.restore();

  ctx.fillStyle = "#ffffff";
  ctx.font = "9px 'Georgia', serif";
  ctx.textAlign = "center";
  ctx.fillText(
    `Education · Discipline · Success   |   EMIS: 66013   |   Est. 2005`,
    W / 2, BOT_Y + BOT_H / 2 + 3
  );
  ctx.textAlign = "left";

  return canvas.toDataURL("image/png", 1.0);
}

// ── Combined download: front + back side by side (portrait cards) ─────────────
async function renderCombined(student: Student, qrUrl: string): Promise<string> {
  const [frontUrl, backUrl] = await Promise.all([renderFront(student, qrUrl), renderBack(student)]);
  const [fi, bi] = await Promise.all([loadImage(frontUrl), loadImage(backUrl)]);
  const PAD = 28;
  const c = document.createElement("canvas");
  c.width = fi.width + bi.width + PAD;
  c.height = Math.max(fi.height, bi.height);
  const ctx = c.getContext("2d")!;
  ctx.fillStyle = "#ffffff";
  ctx.fillRect(0, 0, c.width, c.height);
  ctx.drawImage(fi, 0, (c.height - fi.height) / 2);
  ctx.drawImage(bi, fi.width + PAD, (c.height - bi.height) / 2);
  return c.toDataURL("image/png", 1.0);
}

async function downloadCard(student: Student, qrUrl: string) {
  const dataUrl = await renderCombined(student, qrUrl);
  const a = document.createElement("a");
  a.download = `${student.full_name.replace(/\s+/g, "_")}_Class${student.class}_Roll${student.roll_number}_ID_CARD.png`;
  a.href = dataUrl;
  a.click();
}

// ══════════════════════════════════════════════════════════════════════════════
//  CARD PREVIEW COMPONENT — view-only (no editing). Single download button.
// ══════════════════════════════════════════════════════════════════════════════
const IDCardPreview = ({
  student, frontUrl, backUrl, qrUrl, onClose,
}: {
  student: Student;
  frontUrl: string;
  backUrl: string;
  qrUrl: string;
  onClose: () => void;
}) => {
  const [dl, setDl] = useState(false);
  const [fullView, setFullView] = useState<"front" | "back" | null>(null);

  // Full-screen single side view
  if (fullView) {
    const src = fullView === "front" ? frontUrl : backUrl;
    const label = fullView === "front" ? "Front Side" : "Back Side";
    return (
      <div className="fixed inset-0 z-[60] bg-black/90 flex flex-col items-center justify-center p-3" onClick={() => setFullView(null)}>
        <div className="relative w-full max-w-lg" onClick={e => e.stopPropagation()}>
          {/* Back to both-sides view */}
          <button onClick={() => setFullView(null)} className="absolute -top-10 left-0 text-white/80 hover:text-white text-sm font-medium flex items-center gap-1 transition-colors">
            ← Back to both sides
          </button>
          {/* Close all */}
          <button onClick={onClose} className="absolute -top-10 right-0 p-1.5 rounded-full bg-white/20 hover:bg-white/30 transition-colors">
            <X className="w-4 h-4 text-white" />
          </button>
          <p className="absolute -top-10 left-1/2 -translate-x-1/2 text-white/70 text-xs font-medium">{label}</p>
          <div className="rounded-xl overflow-hidden border border-white/20 shadow-2xl bg-white">
            <img src={src} alt={label} className="w-full block" />
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 z-50 bg-black/70 flex items-center justify-center p-3 overflow-y-auto" onClick={onClose}>
      <div className="relative bg-white dark:bg-slate-900 rounded-2xl shadow-2xl w-full max-w-5xl my-6" onClick={e => e.stopPropagation()}>
        {/* Close button */}
        <button onClick={onClose} className="absolute top-2 right-2 z-20 p-2 rounded-full bg-black/40 hover:bg-black/60 transition-colors">
          <X className="w-5 h-5 text-white" />
        </button>
        <div className="p-4 sm:p-5 space-y-4">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div>
              <p className="text-xs font-semibold text-slate-500 mb-1.5 text-center">FRONT SIDE</p>
              <div
                className="rounded-xl overflow-hidden border border-slate-200 shadow-md bg-white cursor-pointer hover:ring-2 hover:ring-[#0078d4]/50 transition-all group relative"
                onClick={() => setFullView("front")}
              >
                <img src={frontUrl} alt="Front" className="w-full block" />
                <div className="absolute inset-0 bg-black/0 group-hover:bg-black/10 transition-colors flex items-center justify-center">
                  <ZoomIn className="w-8 h-8 text-white opacity-0 group-hover:opacity-80 transition-opacity drop-shadow-lg" />
                </div>
              </div>
            </div>
            <div>
              <p className="text-xs font-semibold text-slate-500 mb-1.5 text-center">BACK SIDE</p>
              <div
                className="rounded-xl overflow-hidden border border-slate-200 shadow-md bg-white cursor-pointer hover:ring-2 hover:ring-[#0078d4]/50 transition-all group relative"
                onClick={() => setFullView("back")}
              >
                <img src={backUrl} alt="Back" className="w-full block" />
                <div className="absolute inset-0 bg-black/0 group-hover:bg-black/10 transition-colors flex items-center justify-center">
                  <ZoomIn className="w-8 h-8 text-white opacity-0 group-hover:opacity-80 transition-opacity drop-shadow-lg" />
                </div>
              </div>
            </div>
          </div>
          <button
            onClick={async () => {
              setDl(true);
              try { await downloadCard(student, qrUrl); toast.success("ID Card downloaded!"); }
              catch { toast.error("Download failed"); }
              finally { setDl(false); }
            }}
            disabled={dl}
            className="w-full flex items-center justify-center gap-2 py-3 rounded-xl bg-[#0078d4] text-white text-sm font-semibold hover:bg-[#106ebe] disabled:opacity-50 transition-colors"
          >
            {dl ? <Loader2 className="w-4 h-4 animate-spin" /> : <Download className="w-4 h-4" />}
            Download ID Card (Front + Back HD PNG)
          </button>
          <p className="text-center text-xs text-slate-400">638×1012 px (CR80 Portrait / 300 dpi) — print-ready HD · Tap a side to zoom</p>
        </div>
      </div>
    </div>
  );
};

// ══════════════════════════════════════════════════════════════════════════════
//  STUDENT ROW — single Download button (front+back combined)
// ══════════════════════════════════════════════════════════════════════════════
const StudentRow = ({
  student, index, onView, downloading, onDownload, onDelete, showDelete,
}: {
  student: Student;
  index: number;
  onView: () => void;
  downloading: boolean;
  onDownload: () => void;
  onDelete?: () => void;
  showDelete?: boolean;
}) => (
  <div className={`flex items-center gap-3 px-4 py-3 border-b border-slate-100 dark:border-slate-800 last:border-0 transition-colors hover:bg-[#eaf4fb] dark:hover:bg-slate-800/30 ${index % 2 === 0 ? "" : "bg-slate-50/40 dark:bg-slate-800/20"}`}>
    {student.photo_url ? (
      <img src={safeMediaUrl(student.photo_url)!} alt="" crossOrigin="anonymous"
        className="w-10 h-10 rounded-full object-cover border-2 border-[#cfe4f7] flex-shrink-0" />
    ) : (
      <div className="w-10 h-10 rounded-full bg-[#eaf4fb] flex items-center justify-center flex-shrink-0">
        <span className="text-[#0078d4] font-bold text-sm">{student.full_name.charAt(0)}</span>
      </div>
    )}
    <div className="flex-1 min-w-0">
      <p className="font-semibold text-sm text-slate-900 dark:text-white truncate">{student.full_name}</p>
      <p className="text-xs text-slate-500">
        Class {student.class} · Roll {student.roll_number}
        {student.serial_no ? ` · ${student.serial_no}` : ""}
      </p>
    </div>
    <div className="flex gap-1.5 flex-shrink-0 flex-wrap justify-end">
      <button onClick={onView}
        className="flex items-center gap-1 px-3 py-1.5 rounded-lg border border-[#0078d4] text-[#0078d4] dark:text-[#4cc2ff] text-xs font-semibold hover:bg-[#eaf4fb] dark:hover:bg-slate-800 transition-colors">
        <ZoomIn className="w-3 h-3" /> View
      </button>
      <button onClick={onDownload} disabled={downloading}
        className="flex items-center gap-1 px-3 py-1.5 rounded-lg bg-[#0078d4] text-white text-xs font-semibold hover:bg-[#106ebe] disabled:opacity-50 transition-colors">
        {downloading ? <Loader2 className="w-3 h-3 animate-spin" /> : <Download className="w-3 h-3" />}
        <span>Download</span>
      </button>
      {showDelete && onDelete && (
        <button onClick={onDelete}
          className="flex items-center gap-1 px-3 py-1.5 rounded-lg border border-red-300 text-red-600 dark:text-red-400 text-xs font-semibold hover:bg-red-50 dark:hover:bg-red-950/30 transition-colors">
          <Trash2 className="w-3 h-3" /> Delete
        </button>
      )}
    </div>
  </div>
);

// ══════════════════════════════════════════════════════════════════════════════
//  MAIN — admin generates cards on demand (class + serial), then list shows
// ══════════════════════════════════════════════════════════════════════════════
type GeneratedCard = { student: Student; frontUrl: string; backUrl: string; qrUrl: string; dbId?: string };

const AdminStudentIDCards = ({ isAdminView = true }: { isAdminView?: boolean }) => {
  const [classFilter, setClassFilter] = useState<string>("");
  const [serialPrefix, setSerialPrefix] = useState<string>("GMSBK-2025");
  const [search, setSearch] = useState("");
  const [generated, setGenerated] = useState<GeneratedCard[]>([]);
  const [generating, setGenerating] = useState(false);
  const [genProgress, setGenProgress] = useState(0);
  const [preview, setPreview] = useState<GeneratedCard | null>(null);
  const [rowDownloading, setRowDownloading] = useState<Record<string, boolean>>({});
  const [bulkLoading, setBulkLoading] = useState(false);
  const [bulkProgress, setBulkProgress] = useState(0);
  const [deleting, setDeleting] = useState<Record<string, boolean>>({});
  const [loadingSaved, setLoadingSaved] = useState(true);

  const { data: studentsData, isLoading: studentsLoading } = useQuery({
    queryKey: ["id-cards-students-pool", classFilter],
    queryFn: async () => {
      if (!classFilter) return [] as Student[];
      let q = supabase
        .from("students")
        .select("id, full_name, roll_number, class, father_name, photo_url, is_active")
        .eq("is_active", true)
        .order("roll_number");
      if (classFilter !== "all") q = q.eq("class", classFilter);
      const { data, error } = await q;
      if (error) throw error;
      return (data ?? []) as Student[];
    },
    enabled: !!classFilter,
    staleTime: 5 * 60 * 1000,
  });

  const availableCount = studentsData?.length ?? 0;

  // ── Load saved cards from database on mount ─────────────────────────────────
  // Both admin and user views load from DB — admin generated cards are visible to students too.
  useEffect(() => {
    (async () => {
      try {
        const { data, error } = await supabase
          .from("generated_id_cards")
          .select("id, student_id, full_name, roll_number, class, father_name, photo_url, is_active, session, serial_no, emis_code")
          .order("class").order("roll_number");
        if (error) throw error;
        if (!data || data.length === 0) { setLoadingSaved(false); return; }

        const out: GeneratedCard[] = [];
        for (const row of data) {
          const s: Student = {
            id: row.student_id,
            full_name: row.full_name,
            roll_number: row.roll_number,
            class: row.class,
            father_name: row.father_name,
            photo_url: row.photo_url,
            is_active: row.is_active,
            session: row.session ?? undefined,
            serial_no: row.serial_no ?? undefined,
            emis_code: row.emis_code ?? undefined,
          };
          const qr = await makeQR(s);
          const [frontUrl, backUrl] = await Promise.all([renderFront(s, qr), renderBack(s)]);
          out.push({ student: s, frontUrl, backUrl, qrUrl: qr, dbId: row.id });
        }
        setGenerated(out);
      } catch (e) {
        console.error("Failed to load saved ID cards:", e);
      } finally {
        setLoadingSaved(false);
      }
    })();
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const handleGenerate = async () => {
    if (!isAdminView) return;
    if (!classFilter) { toast.error("Please select a class"); return; }
    if (!serialPrefix.trim()) { toast.error("Please enter a serial number prefix"); return; }
    if (!studentsData || studentsData.length === 0) { toast.error("No active students found for this class"); return; }
    setGenerating(true); setGenProgress(0);
    try {
      const out: GeneratedCard[] = [];
      const session = `${new Date().getFullYear()}–${new Date().getFullYear() + 1}`;
      for (let i = 0; i < studentsData.length; i++) {
        const s: Student = {
          ...studentsData[i],
          serial_no: `${serialPrefix.trim()}-${String(i + 1).padStart(3, "0")}`,
          session,
          emis_code: "66013",
        };
        const qr = await makeQR(s);
        const [frontUrl, backUrl] = await Promise.all([renderFront(s, qr), renderBack(s)]);

        // Save to database
        let dbId: string | undefined;
        try {
          const { data: inserted, error: dbErr } = await supabase
            .from("generated_id_cards")
            .insert({
              student_id: s.id,
              full_name: s.full_name,
              roll_number: s.roll_number,
              class: s.class,
              father_name: s.father_name,
              photo_url: s.photo_url,
              is_active: s.is_active,
              session: s.session,
              serial_no: s.serial_no,
              emis_code: s.emis_code,
            })
            .select("id")
            .single();
          if (!dbErr && inserted) dbId = inserted.id;
          else console.error("DB save error:", dbErr);
        } catch (dbErr) { console.error("DB save error:", dbErr); }

        out.push({ student: s, frontUrl, backUrl, qrUrl: qr, dbId });
        setGenProgress(Math.round(((i + 1) / studentsData.length) * 100));
      }
      setGenerated(prev => [...prev, ...out]);
      toast.success(`Generated ${out.length} ID card${out.length === 1 ? "" : "s"}`);
    } catch (e) {
      console.error(e);
      toast.error("Failed to generate cards");
    } finally {
      setGenerating(false); setGenProgress(0);
    }
  };

  const handleClearAll = async () => {
    if (!generated.length) return;
    if (typeof window !== "undefined" && !window.confirm("Delete ALL generated ID cards? This cannot be undone.")) return;
    // Delete all from database
    try {
      const dbIds = generated.filter(g => g.dbId).map(g => g.dbId);
      if (dbIds.length > 0) {
        await supabase.from("generated_id_cards").delete().in("id", dbIds);
      }
    } catch (e) { console.error("DB clear error:", e); }
    setGenerated([]);
    setPreview(null);
    toast.success("All generated cards deleted");
  };

  // ── Delete a single card ────────────────────────────────────────────────────
  const handleDeleteOne = async (g: GeneratedCard) => {
    if (typeof window !== "undefined" && !window.confirm(`Delete ID card for ${g.student.full_name}?`)) return;
    setDeleting(p => ({ ...p, [g.student.id]: true }));
    try {
      if (g.dbId) {
        const { error } = await supabase.from("generated_id_cards").delete().eq("id", g.dbId);
        if (error) throw error;
      }
      setGenerated(prev => prev.filter(x => x.student.id !== g.student.id));
      if (preview?.student.id === g.student.id) setPreview(null);
      toast.success("ID card deleted");
    } catch (e) {
      console.error(e);
      toast.error("Failed to delete card");
    } finally {
      setDeleting(p => ({ ...p, [g.student.id]: false }));
    }
  };

  const handleRowDownload = async (g: GeneratedCard) => {
    setRowDownloading(p => ({ ...p, [g.student.id]: true }));
    try {
      await downloadCard(g.student, g.qrUrl);
      toast.success("ID Card downloaded!");
    } catch { toast.error("Download failed"); }
    finally { setRowDownloading(p => ({ ...p, [g.student.id]: false })); }
  };

  const handleBulkZip = async () => {
    if (!generated.length) return;
    setBulkLoading(true); setBulkProgress(0);
    try {
      const { default: JSZip } = await import("jszip");
      const zip = new JSZip();
      for (let i = 0; i < generated.length; i++) {
        const g = generated[i];
        const combined = await renderCombined(g.student, g.qrUrl);
        const blob = await (await fetch(combined)).blob();
        const prefix = `${String(g.student.roll_number).padStart(3, "0")}_${g.student.full_name.replace(/\s+/g, "_")}`;
        zip.folder(`Class_${g.student.class}`)!.file(`${prefix}_ID_CARD.png`, blob);
        setBulkProgress(Math.round(((i + 1) / generated.length) * 100));
      }
      const blob = await zip.generateAsync({ type: "blob" });
      const url = URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.download = `GMS_Babi_Khel_ID_Cards_${classFilter}.zip`;
      a.href = url; a.click();
      URL.revokeObjectURL(url);
      toast.success("ZIP downloaded!");
    } catch { toast.error("Bulk download failed"); }
    finally { setBulkLoading(false); setBulkProgress(0); }
  };

  const filtered = search.trim()
    ? generated.filter(g =>
        g.student.full_name.toLowerCase().includes(search.toLowerCase()) ||
        g.student.roll_number.toLowerCase().includes(search.toLowerCase()))
    : generated;

  return (
    <div className="space-y-5">
      {/* Header */}
      <div>
        <h2 className="text-xl font-bold text-foreground flex items-center gap-2">
          <CreditCard className="w-5 h-5 text-[#0078d4]" />
          Student ID Cards
        </h2>
        <p className="text-xs text-muted-foreground mt-0.5">
          {isAdminView
            ? "Select class & serial prefix, then click Generate to create ID cards"
            : "View your generated ID card"}
        </p>
      </div>

      {/* Admin generate panel */}
      {isAdminView && (
        <div className="rounded-2xl border border-[#cfe4f7] dark:border-slate-700 bg-[#eaf4fb] dark:bg-slate-800/40 p-4 sm:p-5 space-y-4">
          <p className="text-xs font-bold uppercase tracking-wider text-[#0078d4]">Generate ID Cards</p>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
            <div>
              <label className="block text-[10px] uppercase tracking-wider font-bold text-slate-500 mb-1">Class</label>
              <Select value={classFilter} onValueChange={setClassFilter}>
                <SelectTrigger className="w-full bg-white dark:bg-slate-900">
                  <SelectValue placeholder="Select class" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All Classes</SelectItem>
                  {CLASSES.map(c => <SelectItem key={c} value={c}>Class {c}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>
            <div>
              <label className="block text-[10px] uppercase tracking-wider font-bold text-slate-500 mb-1">Serial No. Prefix</label>
              <Input
                value={serialPrefix}
                onChange={e => setSerialPrefix(e.target.value)}
                placeholder="e.g. GMSBK-2025"
                className="bg-white dark:bg-slate-900"
              />
            </div>
            <div className="flex items-end">
              <div className="text-xs text-slate-600 dark:text-slate-400 px-3 py-2 rounded-lg bg-white/60 dark:bg-slate-900/40 w-full">
                {classFilter
                  ? studentsLoading
                    ? "Loading students…"
                    : `${availableCount} active student${availableCount === 1 ? "" : "s"} available`
                  : "Select a class to see student count"}
              </div>
            </div>
          </div>
          <div className="flex flex-col sm:flex-row gap-2">
            <button
              onClick={handleGenerate}
              disabled={generating || !classFilter || studentsLoading || !availableCount}
              className="flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl bg-[#0078d4] text-white text-sm font-semibold hover:bg-[#106ebe] disabled:opacity-50 transition-colors"
            >
              {generating
                ? <><Loader2 className="w-4 h-4 animate-spin" /> Generating {genProgress}%…</>
                : <><CreditCard className="w-4 h-4" /> Generate ID Cards</>}
            </button>
            {generated.length > 0 && (
              <>
                <button
                  onClick={handleBulkZip}
                  disabled={bulkLoading}
                  className="flex items-center justify-center gap-2 px-4 py-2.5 rounded-xl bg-[#106ebe] text-white text-sm font-semibold hover:bg-[#0a5aa0] disabled:opacity-50 transition-colors"
                >
                  {bulkLoading
                    ? <><Loader2 className="w-4 h-4 animate-spin" />{bulkProgress}%</>
                    : <><Download className="w-4 h-4" />Download ZIP ({generated.length})</>}
                </button>
                <button
                  onClick={handleClearAll}
                  disabled={generating || bulkLoading}
                  className="flex items-center justify-center gap-2 px-4 py-2.5 rounded-xl border border-red-300 text-red-600 dark:text-red-400 text-sm font-semibold hover:bg-red-50 dark:hover:bg-red-950/30 disabled:opacity-50 transition-colors"
                >
                  <X className="w-4 h-4" /> Clear All
                </button>
              </>
            )}
          </div>
          {(generating || bulkLoading) && (
            <div className="w-full bg-white dark:bg-slate-700 rounded-full h-2 overflow-hidden">
              <div
                className="h-full bg-[#0078d4] transition-all duration-300 rounded-full"
                style={{ width: `${generating ? genProgress : bulkProgress}%` }}
              />
            </div>
          )}
        </div>
      )}

      {/* Search (only after generation) */}
      {generated.length > 0 && (
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
          <Input
            placeholder="Search generated cards by name or roll number…"
            value={search}
            onChange={e => setSearch(e.target.value)}
            className="pl-9"
          />
        </div>
      )}

      {/* List */}
      {loadingSaved ? (
        <div className="text-center py-16 text-muted-foreground rounded-2xl border-2 border-dashed border-slate-200 dark:border-slate-700">
          <Loader2 className="w-10 h-10 mx-auto mb-3 animate-spin text-[#0078d4]" />
          <p className="text-sm">Loading saved ID cards…</p>
        </div>
      ) : generated.length === 0 ? (
        <div className="text-center py-16 text-muted-foreground rounded-2xl border-2 border-dashed border-slate-200 dark:border-slate-700">
          <CreditCard className="w-10 h-10 mx-auto mb-3 opacity-30" />
          <p className="text-sm">
            {isAdminView
              ? "No ID cards generated yet. Select a class and click Generate."
              : "No ID cards available yet."}
          </p>
        </div>
      ) : filtered.length === 0 ? (
        <div className="text-center py-16 text-muted-foreground">
          <Users className="w-10 h-10 mx-auto mb-3 opacity-30" />
          <p>No matches</p>
        </div>
      ) : (
        <div className="space-y-5">
          {CLASSES.filter(c => filtered.some(g => g.student.class === c)).map(cls => {
            const items = filtered.filter(g => g.student.class === cls);
            if (!items.length) return null;
            return (
              <div key={cls} className="rounded-2xl border border-slate-200 dark:border-slate-700 overflow-hidden shadow-sm bg-white dark:bg-slate-900">
                <div className="flex items-center justify-between px-4 py-3 bg-[#0078d4]">
                  <div className="flex items-center gap-2">
                    <span className="w-7 h-7 rounded-full bg-white/25 text-white font-bold text-sm flex items-center justify-center">{cls}</span>
                    <span className="font-semibold text-white">Class {cls}</span>
                    <span className="text-[#d9ecf9] text-xs">({items.length} card{items.length === 1 ? "" : "s"})</span>
                  </div>
                </div>
                {items.map((g, i) => (
                  <StudentRow
                    key={g.student.id}
                    student={g.student}
                    index={i}
                    onView={() => setPreview(g)}
                    downloading={!!rowDownloading[g.student.id]}
                    onDownload={() => handleRowDownload(g)}
                    onDelete={() => handleDeleteOne(g)}
                    showDelete={isAdminView && !deleting[g.student.id]}
                  />
                ))}
              </div>
            );
          })}
        </div>
      )}

      {preview && (
        <IDCardPreview
          student={preview.student}
          frontUrl={preview.frontUrl}
          backUrl={preview.backUrl}
          qrUrl={preview.qrUrl}
          onClose={() => setPreview(null)}
        />
      )}
    </div>
  );
};

export default AdminStudentIDCards;
export const UserStudentIDCards = () => <AdminStudentIDCards isAdminView={false} />;
